right_example.code:
int factorial(int n) {
  // Base case: điều kiện dừng
  if (n <= 1) {
    return 1;
  }
  // Recursive case: gọi lại với n nhỏ hơn
  return n * factorial(n - 1);
}

printf("%d\n", factorial(5));  // 5 * 4 * 3 * 2 * 1 = 120
printf("%d\n", factorial(0));  // 1

