right_example.code:
// ✅ Cách 1: Đơn giản nhưng chậm O(2^n)
int fib(int n) {
  if (n <= 1) return n;  // Base case: fib(0)=0, fib(1)=1
  return fib(n - 1) + fib(n - 2);
}

// ✅ Cách 2: Tối ưu với memoization O(n)
int memo[100] = {-1};
int fib_memo(int n) {
  if (n <= 1) return n;
  if (memo[n] != -1) return memo[n];  // Đã tính rồi
  memo[n] = fib_memo(n - 1) + fib_memo(n - 2);
  return memo[n];
}

printf("%d\n", fib(10));        // 55 (nhưng chậm)
printf("%d\n", fib_memo(10));  // 55 (nhanh hơn)

